# solution.py
"""Collaborative team / financial planning manager.

This module implements ``TeamCollaborationManager`` -- a thread-safe,
in-memory backend that supports user management, projects, tasks,
messaging (with attachments), performance dashboards, ratings and
exportable reports (CSV / PDF).

Everything is standard-library only so the accompanying unittest suite can
run without third-party dependencies.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Any, Dict, List, Optional, Tuple

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Sentinel used to distinguish "argument omitted" from "argument set to None".
# ---------------------------------------------------------------------------
_UNSET = object()


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role a user can hold within the system."""

    MEMBER = "member"
    ADMIN = "admin"
    VIEWER = "viewer"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime

    def _clone(self) -> "User":
        return copy.copy(self)


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime

    def _clone(self) -> "Project":
        return copy.copy(self)


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None

    def _clone(self) -> "Task":
        return copy.copy(self)


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime

    def _clone(self) -> "Attachment":
        return copy.copy(self)


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    created_at: datetime
    edited_at: Optional[datetime] = None
    attachments: List[Attachment] = field(default_factory=list)

    def _clone(self) -> "Message":
        clone = copy.copy(self)
        clone.attachments = [att._clone() for att in self.attachments]
        return clone


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime

    def _clone(self) -> "Rating":
        return copy.copy(self)


# ---------------------------------------------------------------------------
# Internal stores -- thin data holders that share a single lock.
# ---------------------------------------------------------------------------
class _BaseStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id: Dict[int, User] = {}
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id: Dict[int, Task] = {}
        self.by_project: Dict[int, set] = {}
        self.by_assignee: Dict[int, set] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.by_id: Dict[int, Message] = {}
        self.by_project: Dict[int, set] = {}
        self.by_task: Dict[int, set] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self.ratings_by_ratee: Dict[int, List[Rating]] = {}


class _ReportStore(_BaseStore):
    pass


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory, thread-safe collaboration backend."""

    def __init__(self, now=None) -> None:
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_seq = 0

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # ----- helpers ---------------------------------------------------------
    def _next_id(self) -> int:
        self._id_seq += 1
        return self._id_seq

    def _clock(self) -> datetime:
        return self._now()

    def _require_user(self, user_id: int) -> User:
        user = self.users.by_id.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.by_id.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.by_id.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.by_id.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("Username must be a non-empty string")
            if not isinstance(email, str) or not email.strip():
                raise ValidationError("Email must be a non-empty string")
            if "@" not in email:
                raise ValidationError("Email must contain '@'")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self.users.username_index:
                raise DuplicateError(
                    "Username '{0}' already exists".format(username)
                )
            if email in self.users.email_index:
                raise DuplicateError("Email '{0}' already exists".format(email))

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._clock(),
            )
            self.users.by_id[user.id] = user
            self.users.username_index[username] = user.id
            self.users.email_index[email] = user.id
            return user._clone()

    def get_user(self, user_id) -> User:
        with self._lock:
            return self._require_user(user_id)._clone()

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                self.users.by_id[uid]._clone()
                for uid in sorted(self.users.by_id)
            ]

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not _UNSET:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("Username must be a non-empty string")
                owner = self.users.username_index.get(username)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "Username '{0}' already exists".format(username)
                    )
            if email is not _UNSET:
                if not isinstance(email, str) or not email.strip() or "@" not in email:
                    raise ValidationError("Invalid email")
                owner = self.users.email_index.get(email)
                if owner is not None and owner != user_id:
                    raise DuplicateError(
                        "Email '{0}' already exists".format(email)
                    )
            if role is not _UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not _UNSET and username != user.username:
                del self.users.username_index[user.username]
                self.users.username_index[username] = user_id
                user.username = username
            if email is not _UNSET and email != user.email:
                del self.users.email_index[user.email]
                self.users.email_index[email] = user_id
                user.email = email
            if role is not _UNSET:
                user.role = role
            return user._clone()

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "User owns project {0}".format(project.id)
                    )

            assigned = self.tasks.by_assignee.get(user_id, set())
            for task_id in assigned:
                task = self.tasks.by_id.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "User has open task {0}".format(task_id)
                    )

            # Detach any completed tasks the user owned.
            for task_id in list(assigned):
                task = self.tasks.by_id.get(task_id)
                if task is not None:
                    task.assignee_id = None
            self.tasks.by_assignee.pop(user_id, None)

            del self.users.by_id[user_id]
            self.users.username_index.pop(user.username, None)
            self.users.email_index.pop(user.email, None)
            self.performance.ratings_by_ratee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("Project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._clock(),
            )
            self.projects.by_id[project.id] = project
            self.tasks.by_project.setdefault(project.id, set())
            self.messages.by_project.setdefault(project.id, set())
            return project._clone()

    def get_project(self, project_id) -> Project:
        with self._lock:
            return self._require_project(project_id)._clone()

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self.projects.by_id[pid]._clone()
                for pid in sorted(self.projects.by_id)
            ]

    def update_project(self, project_id, name=_UNSET, description=_UNSET,
                       start_date=_UNSET, end_date=_UNSET) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not _UNSET and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("Project name must be a non-empty string")

            new_start = start_date if start_date is not _UNSET else project.start_date
            new_end = end_date if end_date is not _UNSET else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not _UNSET:
                project.name = name
            if description is not _UNSET:
                project.description = description or ""
            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date
            return project._clone()

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._require_project(project_id)

            task_ids = list(self.tasks.by_project.get(project_id, set()))
            for task_id in task_ids:
                self._remove_task(task_id)

            message_ids = list(self.messages.by_project.get(project_id, set()))
            for message_id in message_ids:
                self._remove_message(message_id)

            self.tasks.by_project.pop(project_id, None)
            self.messages.by_project.pop(project_id, None)
            del self.projects.by_id[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("Task title must be a non-empty string")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            if assignee_id is not None:
                self._require_user(assignee_id)

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._clock(),
            )
            self.tasks.by_id[task.id] = task
            self.tasks.by_project.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self.tasks.by_assignee.setdefault(assignee_id, set()).add(task.id)
            return task._clone()

    def get_task(self, task_id) -> Task:
        with self._lock:
            return self._require_task(task_id)._clone()

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = self.tasks.by_project.get(project_id, set())
            return [self.tasks.by_id[tid]._clone() for tid in sorted(ids)]

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = self.tasks.by_assignee.get(user_id, set())
            return [self.tasks.by_id[tid]._clone() for tid in sorted(ids)]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return task._clone()

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return task._clone()

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return task._clone()

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return task._clone()

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._clock()

            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return task._clone()

    # ----- task helpers ---------------------------------------------------
    def _set_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        old = task.assignee_id
        if old is not None:
            bucket = self.tasks.by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self.tasks.by_assignee.pop(old, None)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks.by_assignee.setdefault(assignee_id, set()).add(task.id)

    def _remove_task(self, task_id: int) -> None:
        task = self.tasks.by_id.pop(task_id, None)
        if task is None:
            return
        if task.assignee_id is not None:
            bucket = self.tasks.by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task_id)
                if not bucket:
                    self.tasks.by_assignee.pop(task.assignee_id, None)
        proj_bucket = self.tasks.by_project.get(task.project_id)
        if proj_bucket is not None:
            proj_bucket.discard(task_id)
        # Cascade messages attached to the task.
        for message_id in list(self.messages.by_task.get(task_id, set())):
            self._remove_message(message_id)
        self.messages.by_task.pop(task_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Provide exactly one of project_id or task_id"
                )
            self._require_user(author_id)
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = list(attachments) if attachments else []
            if (not isinstance(body, str) or not body.strip()) and not attachment_specs:
                raise ValidationError(
                    "Message must have a body or at least one attachment"
                )

            now = self._clock()
            built_attachments = [
                self._build_attachment(spec, author_id, now)
                for spec in attachment_specs
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                created_at=now,
                edited_at=None,
                attachments=built_attachments,
            )
            self.messages.by_id[message.id] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, set()).add(message.id)
            if task_id is not None:
                self.messages.by_task.setdefault(task_id, set()).add(message.id)
            return message._clone()

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("Only the author can edit a message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("Message body must be non-empty")
            message.body = new_body
            message.edited_at = self._clock()
            return message._clone()

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("Only the author can add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            attachment = self._build_attachment(
                (filename, data), user_id, self._clock()
            )
            message.attachments.append(attachment)
            return message._clone()

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = self.messages.by_project.get(project_id, set())
            return [self.messages.by_id[mid]._clone() for mid in sorted(ids)]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = self.messages.by_task.get(task_id, set())
            return [self.messages.by_id[mid]._clone() for mid in sorted(ids)]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("Only the author can delete a message")
            self._remove_message(message_id)

    # ----- message helpers ------------------------------------------------
    def _build_attachment(self, spec: Tuple[str, Any], uploaded_by: int,
                          uploaded_at: datetime) -> Attachment:
        try:
            filename, data = spec
        except (TypeError, ValueError):
            raise ValidationError("Attachment must be a (filename, data) pair")
        if not isinstance(filename, str) or not filename.strip():
            raise ValidationError("Attachment filename must be non-empty")
        if data is None:
            size = 0
        else:
            try:
                size = len(data)
            except TypeError:
                raise ValidationError("Attachment data must be sized")
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=uploaded_at,
        )

    def _remove_message(self, message_id: int) -> None:
        message = self.messages.by_id.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self.messages.by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message_id)
        if message.task_id is not None:
            bucket = self.messages.by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(
                self._tasks_for_assignee(user_id)
            )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("A user cannot rate themselves")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._clock(),
            )
            self.performance.ratings_by_ratee.setdefault(ratee_id, []).append(rating)
            return rating._clone()

    def get_ratings_summary(self, user_id) -> Dict[str, Any]:
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance.ratings_by_ratee.get(user_id, [])
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [r._clone() for r in ratings],
            }

