    # ----- performance helpers -------------------------------------------
    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.tasks.by_assignee.get(user_id, set())
        return [self.tasks.by_id[tid] for tid in ids if tid in self.tasks.by_id]

    @staticmethod
    def _completion_durations(tasks: List[Task]) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations

