    def export_report(self, report, fmt) -> Any:
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    # ----- report export helpers -----------------------------------------
    @staticmethod
    def _export_csv(report: Dict[str, Any]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list):
            columns = report.get("columns")
            if not columns:
                columns = list(rows[0].keys()) if rows else ["value"]
            writer.writerow(columns)
            for row in rows:
                writer.writerow([row.get(col, "") for col in columns])
        else:
            writer.writerow(["metric", "value"])
            for key, value in report.items():
                writer.writerow([key, value])
        return buffer.getvalue()

    @staticmethod
    def _pdf_escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    def _export_pdf(self, report: Dict[str, Any]) -> bytes:
        title = str(report.get("report_type", "report"))
        lines = []
        for key, value in report.items():
            lines.append("{0}: {1}".format(key, value))

        text_commands = ["BT", "/F1 14 Tf", "50 760 Td",
                         "({0}) Tj".format(self._pdf_escape(title))]
        text_commands.append("/F1 11 Tf")
        first = True
        for line in lines:
            leading = "0 -28 Td" if first else "0 -16 Td"
            first = False
            text_commands.append(leading)
            text_commands.append("({0}) Tj".format(self._pdf_escape(line)))
        text_commands.append("ET")
        stream = "\n".join(text_commands).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
            b"<< /Length " + str(len(stream)).encode("ascii") + b" >>\nstream\n"
            + stream + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        out = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(out))
            out += "{0} 0 obj\n".format(index).encode("ascii")
            out += body
            out += b"\nendobj\n"

        xref_pos = len(out)
        count = len(objects) + 1
        out += "xref\n0 {0}\n".format(count).encode("ascii")
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        out += b"trailer\n"
        out += "<< /Size {0} /Root 1 0 R >>\n".format(count).encode("ascii")
        out += b"startxref\n"
        out += "{0}\n".format(xref_pos).encode("ascii")
        out += b"%%EOF\n"
        return bytes(out)
